class BlockchainCommunicator {
    static let shared = BlockchainCommunicator()
    
    private init() {}
    
    func broadcastTransaction(transaction: Transaction, signature: Data) -> Bool {
        let serializedData = transaction.serialize()
        let signatureString = signature.base64EncodedString()
        let url = URL(string: "https://api.blockchain.com/transaction")!
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body = [
            "transaction": serializedData.base64EncodedString(),
            "signature": signatureString
        ]
        
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        let semaphore = DispatchSemaphore(value: 0)
        var success = false
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 {
                success = true
            }
            semaphore.signal()
        }
        
        task.resume()
        semaphore.wait()
        return success
    }
}

